import { describe, expect, it } from 'vitest';
import type { Pipeline, PrefillResult } from '../src/pipeline';
import { PrefillWindowManager } from '../src/prefill-window';

type PrefillCall = {
  tokens: number[];
  startPosOffset: number;
};

class FakePipeline {
  readonly prefillCalls: PrefillCall[] = [];
  readonly savedSessions = new Map<string, number>();
  readonly loadedSessions: string[] = [];
  generateCalls = 0;
  generateFromPrefillCalls = 0;

  async pipelinedPrefill(args: {
    promptTokens: Uint32Array;
    startPosOffset?: number;
  }): Promise<PrefillResult> {
    const tokens = Array.from(args.promptTokens);
    const startPosOffset = args.startPosOffset ?? 0;
    this.prefillCalls.push({ tokens, startPosOffset });
    return {
      logits: new Float32Array([
        (tokens.at(-1) ?? startPosOffset) + startPosOffset + 1,
      ]),
      stationCallCount: 1,
      poisoned: false,
      poisonChunk: -1,
    };
  }

  async generate(args: {
    promptTokens: Uint32Array;
    maxNewTokens: number;
  }): Promise<Uint32Array> {
    this.generateCalls++;
    const prefill = await this.pipelinedPrefill({
      promptTokens: args.promptTokens,
    });
    return this.generateFromPrefill({
      promptTokens: args.promptTokens,
      prefill,
      maxNewTokens: args.maxNewTokens,
    });
  }

  async generateFromPrefill(args: {
    promptTokens: Uint32Array;
    prefill: PrefillResult;
    maxNewTokens: number;
  }): Promise<Uint32Array> {
    this.generateFromPrefillCalls++;
    const out = Array.from(args.promptTokens);
    if (args.maxNewTokens > 0) out.push(args.prefill.logits[0] ?? 0);
    return new Uint32Array(out);
  }

  async saveKvSession(sessionId: string, prefixLength: number): Promise<boolean> {
    this.savedSessions.set(sessionId, prefixLength);
    return true;
  }

  async loadKvSession(sessionId: string): Promise<{ prefixLength: number } | null> {
    this.loadedSessions.push(sessionId);
    const prefixLength = this.savedSessions.get(sessionId);
    return prefixLength === undefined ? null : { prefixLength };
  }

  async deleteKvSession(sessionId: string): Promise<boolean> {
    return this.savedSessions.delete(sessionId);
  }
}

function tokenizeMessages(
  _model: string,
  messages: readonly { content: string }[],
): number[] {
  return messages
    .map((message) => message.content)
    .join('\n')
    .split('')
    .map((char) => char.charCodeAt(0));
}

async function waitForReady(
  manager: PrefillWindowManager,
  id: string,
): Promise<void> {
  for (let i = 0; i < 10; i++) {
    const snapshot = manager.get(id);
    if (snapshot?.state === 'ready') return;
    await Promise.resolve();
  }
  throw new Error(`window ${id} did not become ready`);
}

describe('PrefillWindowManager', () => {
  it('attaches an exact warmed prefix and preserves the generated token path', async () => {
    const pipeline = new FakePipeline();
    const manager = new PrefillWindowManager({
      pipeline: pipeline as unknown as Pipeline,
      tokenizeMessages,
    });
    const messages = [{ role: 'user', content: 'hello' }];
    const snapshot = manager.create({ model: 'gnosis-local', messages });
    await waitForReady(manager, snapshot.id);

    const result = await manager.generate({
      model: 'gnosis-local',
      messages,
      maxNewTokens: 1,
      prefillWindowId: snapshot.id,
    });
    const cold = await pipeline.generate({
      promptTokens: new Uint32Array(tokenizeMessages('gnosis-local', messages)),
      maxNewTokens: 1,
    });

    expect(result.telemetry?.status).toBe('hit');
    expect(result.telemetry?.tokens).toBe(5);
    expect(Array.from(result.tokens)).toEqual(Array.from(cold));
    expect(pipeline.loadedSessions).toContain(snapshot.id);
  });

  it('falls back cold when the final prompt does not start with the warmed token prefix', async () => {
    const pipeline = new FakePipeline();
    const manager = new PrefillWindowManager({
      pipeline: pipeline as unknown as Pipeline,
      tokenizeMessages,
    });
    const snapshot = manager.create({
      model: 'gnosis-local',
      messages: [{ role: 'user', content: 'hello' }],
    });
    await waitForReady(manager, snapshot.id);

    const result = await manager.generate({
      model: 'gnosis-local',
      messages: [{ role: 'user', content: 'hullo' }],
      maxNewTokens: 1,
      prefillWindowId: snapshot.id,
    });

    expect(result.telemetry?.status).toBe('mismatch');
    expect(pipeline.generateCalls).toBe(1);
  });

  it('uses appendable prefill when an update extends the exact warmed token prefix', async () => {
    const pipeline = new FakePipeline();
    const manager = new PrefillWindowManager({
      pipeline: pipeline as unknown as Pipeline,
      tokenizeMessages,
    });
    const snapshot = manager.create({
      model: 'gnosis-local',
      messages: [{ role: 'user', content: 'hello' }],
    });
    await waitForReady(manager, snapshot.id);

    manager.update(snapshot.id, {
      messages: [{ role: 'user', content: 'hello!' }],
    });
    await waitForReady(manager, snapshot.id);

    expect(pipeline.prefillCalls.at(-1)).toEqual({
      tokens: ['!'.charCodeAt(0)],
      startPosOffset: 5,
    });
  });

  it('expires old windows and treats attached chat as cold generation', async () => {
    let now = 1_000;
    const pipeline = new FakePipeline();
    const manager = new PrefillWindowManager({
      pipeline: pipeline as unknown as Pipeline,
      tokenizeMessages,
      now: () => now,
      defaultTtlMs: 10,
    });
    const snapshot = manager.create({
      model: 'gnosis-local',
      messages: [{ role: 'user', content: 'hello' }],
    });
    await waitForReady(manager, snapshot.id);

    now = 2_000;
    const result = await manager.generate({
      model: 'gnosis-local',
      messages: [{ role: 'user', content: 'hello' }],
      maxNewTokens: 1,
      prefillWindowId: snapshot.id,
    });

    expect(result.telemetry?.status).toBe('expired');
    expect(result.telemetry?.missReason).toBe('expired window');
    expect(pipeline.generateCalls).toBe(1);
  });
});
